# --- 1. Model Downloading and Loading ---
def download_and_load_model(model_url, local_path="downloaded_model.pth"):
    if os.path.exists(local_path):
        print(f"Loading model from existing local file: {local_path}")
        model_state_dict = torch.load(local_path, map_location=DEVICE)
    else:
        print(f"Downloading model from: {model_url}")
        try:
            response = requests.get(model_url, stream=True)
            response.raise_for_status() # Raise an HTTPError for bad responses (4xx or 5xx)

            # Save to a temporary buffer first, then to disk to handle potential large files
            # or directly load from bytes if file is small and can fit in memory
            # For larger files, it's better to save to disk chunk by chunk
            with open(local_path, 'wb') as f:
                for chunk in response.iter_content(chunk_size=8192):
                    f.write(chunk)
            print(f"Model downloaded and saved to: {local_path}")
            model_state_dict = torch.load(local_path, map_location=DEVICE)
        except requests.exceptions.RequestException as e:
            print(f"Error downloading model: {e}")
            raise
        except Exception as e:
            print(f"Error loading downloaded model: {e}")
            raise
    return model_state_dict

def prepare_model_for_finetuning(num_classes, pretrained_state_dict=None):
    if pretrained_state_dict:
        # Load a model with pre-defined weights using state_dict
        model = resnet18(weights=None) # Start with an untrained model structure
        model.load_state_dict(pretrained_state_dict)
    else:
        # Load a pre-trained model directly from torchvision using built-in weights
        print(f"Loading pre-trained {MODEL_ARCH} from torchvision...")
        weights = MODEL_WEIGHTS
        model = globals()[MODEL_ARCH](weights=weights)

    # Freeze all parameters in the network
    # for param in model.parameters():
    #     param.requires_grad = False

    # Replace the final classification layer
    num_ftrs = model.fc.in_features
    model.fc = nn.Linear(num_ftrs, num_classes)
    return model

# --- 2. Custom Dataset and DataLoader ---
# Using CIFAR-10 as an example custom dataset for simplicity
# You would replace this with your actual custom dataset class

class CustomDataset(Dataset):
    def __init__(self, data, targets, transform=None):
        self.data = data
        self.targets = targets
        self.transform = transform

    def __len__(self):
        return len(self.data)

    def __getitem__(self, idx):
        img = self.data[idx]
        label = self.targets[idx]
        if self.transform:
            img = self.transform(img)
        return img, label

def get_dataloaders(batch_size, num_classes):
    # Data transformations
    transform_train = transforms.Compose([
        transforms.RandomCrop(32, padding=4),
        transforms.RandomHorizontalFlip(),
        transforms.ToTensor(),
        transforms.Normalize((0.4914, 0.4822, 0.4465), (0.2023, 0.1994, 0.2010)),
    ])

    transform_test = transforms.Compose([
        transforms.ToTensor(),
        transforms.Normalize((0.4914, 0.4822, 0.4465), (0.2023, 0.1994, 0.2010)),
    ])

    # Load CIFAR-10 dataset
    train_dataset = CIFAR10(root='./data', train=True, download=True, transform=transform_train)
    test_dataset = CIFAR10(root='./data', train=False, download=True, transform=transform_test)

    train_loader = DataLoader(train_dataset, batch_size=batch_size, shuffle=True, num_workers=2)
    test_loader = DataLoader(test_dataset, batch_size=batch_size, shuffle=False, num_workers=2)

    return train_loader, test_loader

# --- 3. Fine-tuning Loop ---
def train_model(model, train_loader, test_loader, criterion, optimizer, num_epochs, device, output_path):
    best_accuracy = 0.0

    model.to(device)

    for epoch in range(num_epochs):
        print(f"Epoch {epoch+1}/{num_epochs}")
        print("-" * 10)

        # Training phase
        model.train()
        running_loss = 0.0
        correct_predictions = 0
        total_samples = 0

        for i, (inputs, labels) in enumerate(train_loader):
            inputs, labels = inputs.to(device), labels.to(device)

            optimizer.zero_grad()

            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()

            running_loss += loss.item() * inputs.size(0)
            _, predicted = torch.max(outputs.data, 1)
            total_samples += labels.size(0)
            correct_predictions += (predicted == labels).sum().item()

        epoch_loss = running_loss / total_samples
        epoch_accuracy = correct_predictions / total_samples
        print(f"Train Loss: {epoch_loss:.4f} Acc: {epoch_accuracy:.4f}")

        # Evaluation phase
        model.eval()
        running_loss = 0.0
        correct_predictions = 0
        total_samples = 0

        with torch.no_grad():
            for inputs, labels in test_loader:
                inputs, labels = inputs.to(device), labels.to(device)

                outputs = model(inputs)
                loss = criterion(outputs, labels)

                running_loss += loss.item() * inputs.size(0)
                _, predicted = torch.max(outputs.data, 1)
                total_samples += labels.size(0)
                correct_predictions += (predicted == labels).sum().item()

        epoch_loss = running_loss / total_samples
        epoch_accuracy = correct_predictions / total_samples
        print(f"Val Loss: {epoch_loss:.4f} Acc: {epoch_accuracy:.4f}")

        # Save the best model
        if epoch_accuracy > best_accuracy:
            best_accuracy = epoch_accuracy
            torch.save(model.state_dict(), output_path)
            print(f"Model saved to {output_path} with improved accuracy: {best_accuracy:.4f}")

    print("Fine-tuning complete!")
    print(f"Best validation accuracy: {best_accuracy:.4f}")
    return model

